const body = $node['Webhook Trigger'].json.body || {};
const response = $input.first()?.json || {};
const results = Array.isArray(response.results) ? response.results : [];

const candidateSkills = Array.isArray(body.skills)
  ? body.skills
  : typeof body.skills === 'string'
  ? body.skills.split(',').map(s => s.trim()).filter(Boolean)
  : [];

const base = {
  candidateName: body.name || body.studentName || body.fullName || 'Candidate',
  candidateEmail: body.email || body.studentEmail || '',
  candidateSkills,
  targetRole: body.keyword || body.targetRole || body.role || 'software developer',
  location: body.location || body.city || 'Bangalore',
  resumeLink: body.resumeLink || body.resume || '',
  minScore: Number(body.minScore ?? 5)
};

if (results.length === 0) {
  return [
    {
      json: {
        ...base,
        noJobsFound: true
      }
    }
  ];
}

return results.map(job => {
  return {
    json: {
      ...base,
      noJobsFound: false,
      jobTitle: job.title || 'Unknown Role',
      company: job.company?.display_name || 'Unknown Company',
      jobLocation: job.location?.display_name || base.location,
      jobDescription: job.description || '',
      applyUrl: job.redirect_url || '',
      salaryMin: job.salary_min ?? null,
      salaryMax: job.salary_max ?? null,
      publishedAt: job.created || job.created_at || '',
      source: 'Adzuna'
    }
  };
});

