const scoredItems = $input.all();
const originalJobs = $items('Normalize Jobs');
const body = $node['Webhook Trigger'].json.body || {};
const threshold = Number(body.minScore ?? 5);
const matches = [];

function extractContent(raw) {
  return raw?.choices?.[0]?.message?.content
    ?? raw?.data?.choices?.[0]?.message?.content
    ?? raw?.response?.choices?.[0]?.message?.content
    ?? '';
}

function parseModelJson(content) {
  try {
    const cleaned = String(content || '')
      .replace(/json/gi, '')
      .replace(/```/g, '')
      .trim();

    const match = cleaned.match(/\{[\s\S]*\}/);
    const candidate = match ? match[0] : cleaned;
    return JSON.parse(candidate);
  } catch (e) {
    return {
      score: 0,
      reason: 'Could not parse model response',
      skills_needed: []
    };
  }
}

for (let i = 0; i < scoredItems.length; i++) {
  const raw = scoredItems[i].json || {};
  const job = originalJobs[i]?.json || {};
  const parsed = parseModelJson(extractContent(raw));
  const score = Math.max(0, Math.min(10, Number(parsed.score) || 0));

  if (score < threshold) continue;

  const candidateName = job.candidateName || 'Candidate';
  const candidateSkills = Array.isArray(job.candidateSkills) ? job.candidateSkills : [];
  const resumeLink = job.resumeLink || '';

  const emailSubject = `Application for ${job.jobTitle} at ${job.company}`;
  const emailDraft = [
    `Subject: ${emailSubject}`,
    '',
    `Hello ${job.company} Hiring Team,`,
    '',
    `I am interested in the ${job.jobTitle} role. My background and skills align with this opportunity.`,
    '',
    `Relevant skills: ${candidateSkills.length ? candidateSkills.join(', ') : 'Not provided'}`,
    `Match reason: ${parsed.reason || 'Strong relevance'}`,
    `Suggested skills to highlight: ${(Array.isArray(parsed.skills_needed) && parsed.skills_needed.length) ? parsed.skills_needed.join(', ') : 'None'}`,
    '',
    `Resume: ${resumeLink || 'Not provided'}`,
    `Apply link: ${job.applyUrl || 'Not provided'}`,
    '',
    'Best regards,',
    candidateName
  ].join('\n');

  matches.push({
    candidateName,
    candidateEmail: job.candidateEmail || '',
    candidateSkills,
    targetRole: job.targetRole,
    location: job.location,
    jobTitle: job.jobTitle,
    company: job.company,
    jobLocation: job.jobLocation,
    jobDescription: job.jobDescription,
    applyUrl: job.applyUrl,
    salaryMin: job.salaryMin,
    salaryMax: job.salaryMax,
    publishedAt: job.publishedAt,
    source: job.source,
    score,
    reason: parsed.reason || '',
    skills_needed: Array.isArray(parsed.skills_needed) ? parsed.skills_needed : [],
    emailSubject,
    emailDraft
  });
}

matches.sort((a, b) => b.score - a.score);

return [
  {
    json: {
      status: 'success',
      totalScored: scoredItems.length,
      totalMatched: matches.length,
      threshold,
      jobs: matches.slice(0, 10),
      timestamp: new Date().toISOString()
    }
  }
];

const body = $node['Webhook Trigger'].json.body || {};

return [
  {
    json: {
      status: 'success',
      totalScored: 0,
      totalMatched: 0,
      threshold: Number(body.minScore ?? 5),
      jobs: [],
      message: 'No jobs found for the given query.',
      timestamp: new Date().toISOString()
    }
  }
];

const aggregateResult = $items('Aggregate And Build Response')[0]?.json || {};
const aiGuidance = $items('AI Career Agent')[0]?.json || {};

function extractContent(raw) {
  return raw?.choices?.[0]?.message?.content
    ?? raw?.data?.choices?.[0]?.message?.content
    ?? raw?.response?.choices?.[0]?.message?.content
    ?? '';
}

const careerGuidance = extractContent(aiGuidance);

return [
  {
    json: {
      ...aggregateResult,
      aiCareerGuidance: careerGuidance || 'Career guidance not available'
    }
  }
];
